return [
  {
    json: {
      baseUrl: 'https://bilig.proompteng.ai',
      sheetName: 'Inputs',
      address: 'B3',
      value: 0.4,
      note: 'Change one forecast input, then require computed formula readback.'
    }
  }
];

const proof = $input.first().json;

if (proof.verified !== true) {
  throw new Error(`Bilig WorkPaper did not verify the edit: ${JSON.stringify(proof)}`);
}

if (typeof proof.editedCell !== 'string' || !proof.editedCell.startsWith('Inputs!')) {
  throw new Error(`Expected an Inputs sheet edit, received ${proof.editedCell}`);
}

if (!proof.checks?.formulasPersisted || !proof.checks?.restoredMatchesAfter || !proof.checks?.computedOutputChanged) {
  throw new Error(`Formula proof checks failed: ${JSON.stringify(proof.checks)}`);
}

if (typeof proof.after?.expectedArr !== 'number' || typeof proof.after?.targetGap !== 'number') {
  throw new Error(`Unexpected formula output: ${JSON.stringify(proof.after)}`);
}

return [
  {
    json: {
      verdict: 'verified',
      editedCell: proof.editedCell,
      beforeExpectedArr: proof.before.expectedArr,
      afterExpectedArr: proof.after.expectedArr,
      targetGap: proof.after.targetGap,
      checks: proof.checks,
      github: 'https://github.com/proompteng/bilig'
    }
  }
];
